UPDATE comments
SET content = #{content}
WHERE id = #{id} AND `쉼표번호` = #{commaNo} AND status = 'visible'

UPDATE comments
SET content = #{content}, status = #{status}
WHERE id = #{id} AND `쉼표번호` = #{commaNo}

UPDATE comments
SET status = 'deleted'
WHERE id = #{id} AND `쉼표번호` = #{commaNo}
